import { InventoryContext } from '../../../../../../../../../src/api/contexts/inventory/InventoryContext';

export class InventoryStore {
    private static _items: InventoryContext[] = [];
    private static _listeners = new Set<(items: InventoryContext[]) => void>();

    static setItems(items: InventoryContext[]) {
        this._items = items;
        this._listeners.forEach((cb) => cb(this._items));
    }

    static getItems(): InventoryContext[] {
        return this._items;
    }

    /** subscribe; returns an unsubscribe function */
    static onUpdate(callback: (items: InventoryContext[]) => void): () => void {
        this._listeners.add(callback);
        // push current state immediately so UI mounts with data
        callback(this._items);
        return () => this._listeners.delete(callback);
    }

    static clearListeners() {
        this._listeners.clear();
    }
}
